"use client";

import { useEffect, useState } from "react";
import { ChevronLeft, Inbox, Trash2, CheckCircle2, BookOpen, Brain, Clock, ShieldAlert } from "lucide-react";
import Link from "next/link";
import { getDeferredItemsAction, manageInboxItemAction } from "@/app/actions";
import { useToast } from "@/components/ToastProvider";
import { motion, AnimatePresence } from "framer-motion";

export default function InboxPage() {
    const { showToast } = useToast();
    const [isLoading, setIsLoading] = useState(true);
    const [vocab, setVocab] = useState<any[]>([]);

    const fetchData = async () => {
        setIsLoading(true);
        const res = await getDeferredItemsAction();
        if (res.success) {
            setVocab(res.vocab || []);
        } else {
            showToast(res.error || "Không thể tải dữ liệu Inbox.", "error");
        }
        setIsLoading(false);
    };

    useEffect(() => {
        fetchData();
    }, []);

    const handleAction = async (id: string, type: "VOCAB" | "GRAMMAR", action: "ADD" | "DELETE") => {
        const res = await manageInboxItemAction(id, type, action);
        if (res.success) {
            showToast(action === "ADD" ? "Đã chuyển vào tổ ong chính! 🐝" : "Đã xóa khỏi Inbox.", "success");
            fetchData();
        } else {
            showToast(res.error || "Thao tác thất bại.", "error");
        }
    };

    return (
        <main className="flex min-h-screen flex-col items-center bg-slate-50 dark:bg-slate-950 transition-colors font-sans px-4 pb-20">
            {/* Header */}
            <header className="w-full max-w-4xl flex justify-between items-center py-8">
                <Link href="/" className="p-3 bg-white dark:bg-white/5 rounded-2xl shadow-sm hover:shadow-md transition-all text-slate-600 dark:text-slate-400">
                    <ChevronLeft size={24} />
                </Link>
                <div className="text-center">
                    <h1 className="text-3xl font-black text-slate-800 dark:text-white flex items-center justify-center gap-3">
                        <Inbox className="text-blue-500" /> Inbox Backlog
                    </h1>
                    <p className="text-sm font-bold text-slate-400 uppercase tracking-widest mt-1">Weekly Catch-up Session</p>
                </div>
                <div className="w-12 h-12" /> {/* Spacer */}
            </header>

            <div className="w-full max-w-4xl space-y-8 mt-4">
                {isLoading ? (
                    <div className="flex flex-col items-center justify-center py-20 gap-4">
                        <div className="w-12 h-12 border-4 border-blue-500/20 border-t-blue-500 rounded-full animate-spin" />
                        <p className="text-slate-400 font-bold animate-pulse uppercase text-xs tracking-widest">Đang quét tổ ong...</p>
                    </div>
                ) : vocab.length === 0 ? (
                    <div className="text-center py-20 glass dark:bg-slate-900/50 rounded-[3rem] border border-white/20">
                        <span className="text-6xl block mb-6">🎉</span>
                        <h2 className="text-xl font-black text-slate-700 dark:text-slate-200">Inbox trống trơn!</h2>
                        <p className="text-slate-500 text-sm mt-2">Bạn đã xử lý hết mọi nội dung từ đề thi rồi. Tuyệt vời!</p>
                        <Link href="/" className="inline-block mt-8 px-8 py-3 bg-blue-500 text-white font-black rounded-2xl shadow-lg shadow-blue-500/20 hover:scale-105 transition-all">VỀ TRANG CHỦ</Link>
                    </div>
                ) : (
                    <>
                        {/* Summary Alert */}
                        <div className="p-6 bg-blue-500/10 border border-blue-500/20 rounded-3xl flex items-start gap-4">
                            <ShieldAlert className="text-blue-500 shrink-0" size={24} />
                            <div>
                                <h3 className="text-sm font-black text-blue-600 dark:text-blue-400 uppercase tracking-tight">Quy tắc Weekly Catch-up</h3>
                                <p className="text-xs text-blue-600/70 dark:text-blue-400/70 font-bold mt-1 leading-relaxed">
                                    Đừng cố dồn tất cả vào SRS chính. Chỉ chọn 10-15 nội dung quan trọng nhất để chuyển đổi (Promote) mỗi tuần. Những cái còn lại hãy mạnh dạn xóa bỏ!
                                </p>
                            </div>
                        </div>

                        {/* Vocabulary Section */}
                        {vocab.length > 0 && (
                            <section className="space-y-4">
                                <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest px-4">Từ vựng chờ xử lý ({vocab.length})</h3>
                                <div className="grid grid-cols-1 gap-3">
                                    <AnimatePresence mode="popLayout">
                                        {vocab.map((item) => (
                                            <InboxCard
                                                key={item.id}
                                                title={item.word}
                                                subtitle={item.meaning}
                                                score={item.importanceScore}
                                                type="VOCAB"
                                                onAdd={() => handleAction(item.id, "VOCAB", "ADD")}
                                                onDelete={() => handleAction(item.id, "VOCAB", "DELETE")}
                                            />
                                        ))}
                                    </AnimatePresence>
                                </div>
                            </section>
                        )}
                    </>
                )}
            </div>
        </main>
    );
}

function InboxCard({ title, subtitle, score, type, onAdd, onDelete }: any) {
    return (
        <motion.div
            layout
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 20 }}
            className="group flex items-center gap-4 p-4 glass dark:bg-slate-900/80 rounded-2xl border border-white/20 dark:border-white/5 hover:border-blue-500/30 transition-all shadow-sm hover:shadow-md"
        >
            <div className={`p-3 rounded-xl shrink-0 ${type === "VOCAB" ? "bg-orange-500/10 text-orange-500" : "bg-purple-500/10 text-purple-500"}`}>
                {type === "VOCAB" ? <BookOpen size={20} /> : <Brain size={20} />}
            </div>

            <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2 mb-0.5">
                    <h4 className="font-black text-slate-700 dark:text-slate-200 truncate leading-tight">{title}</h4>
                    <span className="px-2 py-0.5 bg-slate-100 dark:bg-white/5 rounded-md text-[9px] font-black text-slate-400">SCORE: {score}</span>
                </div>
                <p className="text-xs font-medium text-slate-500 truncate">{subtitle}</p>
            </div>

            <div className="flex items-center gap-2 pr-2">
                <button
                    onClick={onDelete}
                    className="p-2.5 text-slate-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-500/10 rounded-xl transition-all"
                    title="Xóa"
                >
                    <Trash2 size={18} />
                </button>
                <button
                    onClick={onAdd}
                    className="p-2.5 bg-blue-500 text-white rounded-xl shadow-lg shadow-blue-500/20 hover:scale-105 active:scale-95 transition-all flex items-center gap-2 px-5"
                >
                    <CheckCircle2 size={18} />
                    <span className="text-[11px] font-black hidden md:block">PROMOTE</span>
                </button>
            </div>
        </motion.div>
    );
}

import type { Metadata } from "next";
import "./globals.css";
import { ThemeProvider } from "@/components/ThemeProvider";
import { ToastProvider } from "@/components/ToastProvider";

export const metadata: Metadata = {
  title: "VocaBee - Hàng xóm của bạn 🐝",
  description: "Ứng dụng học từ vựng SRS thông minh",
};

export default function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <html lang="en" suppressHydrationWarning>
      <head>
        <link rel="preconnect" href="https://fonts.googleapis.com" />
        <link rel="preconnect" href="https://fonts.gstatic.com" crossOrigin="" />
        <link href="https://fonts.googleapis.com/css2?family=Lexend:wght@300;400;500;600;700;800&display=swap" rel="stylesheet" />
        <link href="https://fonts.googleapis.com/css2?family=Plus+Jakarta+Sans:wght@200..800&display=swap" rel="stylesheet" />
        <link href="https://fonts.googleapis.com/css2?family=Material+Symbols+Outlined:wght,FILL@100..700,0..1&display=swap" rel="stylesheet" />
      </head>
      <body className="antialiased">
        <ThemeProvider
          attribute="class"
          defaultTheme="system"
          enableSystem
          disableTransitionOnChange
        >
          <ToastProvider>
            {children}
          </ToastProvider>
        </ThemeProvider>
      </body>
    </html>
  );
}

// app/leaderboard/page.tsx
import { auth } from '@/auth';
import { redirect } from 'next/navigation';
import { getAuthenticatedUser } from '@/lib/user';
import Sidebar from '@/components/Sidebar';
import { getLeaderboardAction, getDashboardStats } from '@/app/actions';
import { ThemeToggle } from '@/components/ThemeToggle';
import { Crown, Trophy, Medal } from 'lucide-react';

export const dynamic = 'force-dynamic';

export default async function LeaderboardPage() {
    const session = await auth();

    if (!session) {
        redirect('/login');
    }

    const user = await getAuthenticatedUser();
    const leaderboardData = await getLeaderboardAction();
    const stats = await getDashboardStats();

    if ('error' in leaderboardData) {
        return <div>Lỗi khi tải bảng xếp hạng: {leaderboardData.error}</div>;
    }

    const users = leaderboardData.users || [];
    const top3 = users.slice(0, 3);
    const others = users.slice(3);
    const currentUserRank = users.findIndex(u => u.id === user?.id) + 1;

    return (
        <div className="flex min-h-screen bg-background text-foreground font-sans">
            <Sidebar />

            <main className="flex-1 md:ml-64 relative h-screen overflow-y-auto no-scrollbar bg-background transition-colors">
                {/* Sticky Header */}
                <header className="sticky top-0 z-20 bg-background/80 backdrop-blur-xl px-4 sm:px-8 py-5 flex items-center justify-between border-b border-glass-border">
                    <div className="flex items-center gap-4">
                        <button className="md:hidden text-foreground p-2 rounded-lg hover:bg-surface/50">
                            <span className="material-symbols-outlined">menu</span>
                        </button>
                        <h2 className="text-foreground text-xl font-bold tracking-tight hidden md:block text-shadow-gold">Bảng vinh danh</h2>
                    </div>

                    <div className="flex items-center gap-4 md:gap-6">
                        <div className="hidden md:flex items-center gap-2 bg-surface/50 border border-glass-border px-3 py-1.5 rounded-full backdrop-blur-sm">
                            <span className="material-symbols-outlined text-amber-500 text-[20px] filled">local_fire_department</span>
                            <span className="text-amber-500 font-bold text-sm">{stats?.streak || 0}</span>
                        </div>
                        <div className="hidden md:flex items-center gap-2 bg-surface/50 border border-glass-border px-3 py-1.5 rounded-full backdrop-blur-sm">
                            <span className="material-symbols-outlined text-primary text-[20px] filled">hive</span>
                            <span className="text-primary font-bold text-sm">{(stats?.points || 0).toLocaleString()}</span>
                        </div>
                        <div className="h-8 w-px bg-glass-border mx-1 md:mx-2"></div>
                        <ThemeToggle />
                    </div>
                </header>

                <div className="p-4 sm:p-6 max-w-5xl mx-auto flex flex-col gap-12 pb-24 pt-8">
                    {/* Podium / Top 3 Section */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-end">
                        {/* 2nd Place */}
                        {top3[1] && (
                            <div className="order-2 md:order-1 flex flex-col items-center gap-4 pt-8 md:pt-16">
                                <div className="relative group">
                                    <div className="w-24 h-24 rounded-full bg-slate-200 dark:bg-slate-800 border-4 border-slate-400/50 shadow-lg flex items-center justify-center text-4xl group-hover:scale-105 transition-transform">
                                        🥈
                                    </div>
                                    <div className="absolute -top-4 -right-2 bg-slate-400 text-white w-8 h-8 rounded-full flex items-center justify-center font-bold border-2 border-background">2</div>
                                </div>
                                <div className="text-center">
                                    <h3 className="font-bold text-lg truncate max-w-[150px]">{top3[1].name}</h3>
                                    <p className="text-slate-500 font-medium">{top3[1].points.toLocaleString()} XP</p>
                                </div>
                            </div>
                        )}

                        {/* 1st Place */}
                        {top3[0] && (
                            <div className="order-1 md:order-2 flex flex-col items-center gap-4 relative">
                                <div className="absolute -top-12 left-1/2 -translate-x-1/2 animate-bounce">
                                    <Crown className="text-primary w-12 h-12 drop-shadow-glow" />
                                </div>
                                <div className="relative group">
                                    <div className="w-32 h-32 rounded-full bg-amber-100 dark:bg-amber-900/30 border-4 border-primary shadow-glow flex items-center justify-center text-5xl group-hover:scale-110 transition-all duration-500">
                                        🥇
                                    </div>
                                    <div className="absolute -top-4 -right-2 bg-primary text-black w-10 h-10 rounded-full flex items-center justify-center font-black border-2 border-background shadow-lg">1</div>
                                </div>
                                <div className="text-center">
                                    <h3 className="font-black text-2xl text-gradient-amber tracking-tight">{top3[0].name}</h3>
                                    <p className="text-amber-500 font-bold text-lg">{top3[0].points.toLocaleString()} XP</p>
                                </div>
                            </div>
                        )}

                        {/* 3rd Place */}
                        {top3[2] && (
                            <div className="order-3 flex flex-col items-center gap-4 pt-8 md:pt-16">
                                <div className="relative group">
                                    <div className="w-24 h-24 rounded-full bg-orange-100 dark:bg-orange-900/20 border-4 border-orange-400/50 shadow-lg flex items-center justify-center text-4xl group-hover:scale-105 transition-transform">
                                        🥉
                                    </div>
                                    <div className="absolute -top-4 -right-2 bg-orange-400 text-white w-8 h-8 rounded-full flex items-center justify-center font-bold border-2 border-background">3</div>
                                </div>
                                <div className="text-center">
                                    <h3 className="font-bold text-lg truncate max-w-[150px]">{top3[2].name}</h3>
                                    <p className="text-slate-500 font-medium">{top3[2].points.toLocaleString()} XP</p>
                                </div>
                            </div>
                        )}
                    </div>

                    {/* Rankings List */}
                    <div className="glass-panel rounded-[2rem] border border-glass-border overflow-hidden shadow-soft">
                        <div className="p-6 border-b border-glass-border bg-surface/30">
                            <h3 className="text-sm font-black text-slate-400 uppercase tracking-[0.2em]">Bảng xếp hạng đầy đủ</h3>
                        </div>
                        <div className="divide-y divide-glass-border">
                            {others.map((u, i) => {
                                const isCurrentUser = u.id === user?.id;
                                return (
                                    <div
                                        key={u.id}
                                        className={`flex items-center gap-4 p-5 transition-colors hover:bg-surface/50 ${isCurrentUser ? 'bg-primary/10' : ''}`}
                                    >
                                        <div className="w-8 font-bold text-slate-400 text-center">{i + 4}</div>
                                        <div className="w-10 h-10 rounded-full bg-surface/50 flex items-center justify-center text-lg border border-glass-border self-center">
                                            👤
                                        </div>
                                        <div className="flex-1">
                                            <p className={`font-bold ${isCurrentUser ? 'text-primary' : 'text-foreground'}`}>
                                                {u.name} {isCurrentUser && '(Bạn)'}
                                            </p>
                                            <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">{u.streakCount} Day Streak</p>
                                        </div>
                                        <div className="text-right">
                                            <p className="font-black text-foreground">{u.points.toLocaleString()} <span className="text-[10px] text-slate-500">XP</span></p>
                                        </div>
                                    </div>
                                );
                            })}
                        </div>
                    </div>

                    {/* Current User Float Banner */}
                    {user && currentUserRank > 3 && (
                        <div className="mt-8 amber-glass-gradient rounded-2xl p-6 flex items-center justify-between border border-primary/20 shadow-glow animate-in slide-in-from-bottom-4 duration-500">
                            <div className="flex items-center gap-4">
                                <div className="bg-primary text-black font-black w-10 h-10 rounded-full flex items-center justify-center shadow-lg">
                                    {currentUserRank}
                                </div>
                                <div>
                                    <p className="font-bold text-foreground">Xếp hạng của bạn</p>
