                            <span className="text-[10px] font-black uppercase tracking-widest">SM-2 Ready</span>
                        </div>
                        <div className="flex-1" />
                        <div className="flex w-full sm:w-auto gap-3">
                            <button
                                onClick={onClose}
                                className="flex-1 sm:flex-none px-6 py-3.5 rounded-2xl text-sm font-bold text-slate-500 hover:bg-slate-100 dark:hover:bg-white/5 transition-all"
                            >
                                HỦY BỎ
                            </button>
                            <button
                                onClick={handleSave}
                                disabled={isLoading || !prompt.trim() || !answer.trim() || !myError.trim()}
                                className="flex-1 sm:flex-none px-10 py-3.5 bg-gradient-to-r from-purple-600 to-indigo-600 dark:from-purple-500 dark:to-indigo-500 text-white rounded-2xl text-sm font-black shadow-lg shadow-purple-500/20 hover:shadow-purple-500/40 hover:scale-[1.02] active:scale-95 disabled:opacity-50 disabled:scale-100 transition-all flex items-center justify-center gap-2"
                            >
                                {isLoading ? (
                                    <>
                                        <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                                        ĐANG LƯU...
                                    </>
                                ) : (
                                    <>
                                        <Check size={18} />
                                        LƯU LỖI SAI 🐝
                                    </>
                                )}
                            </button>
                        </div>
                    </div>
                </div>
            </motion.div>
        </div>
    );
}

