import { describe, it, expect } from 'vitest';
import { calculateSm2 } from './sm2';

/**
 * SM-2 Algorithm Implementation Details (for reference):
 * - Initial state: interval=0, repetition=0, efactor=2.5
 * - Correct (Q >= 3):
 *   - Repetition 0 -> Int=1, Rep=1
 *   - Repetition 1 -> Int=6, Rep=2
 *   - Repetition > 1 -> Int=Round(Int * EF), Rep++
 * - Incorrect (Q < 3):
 *   - Int=1, Rep=0, EF down
 * - EF formula: EF' = EF + (0.1 - (5-q) * (0.08 + (5-q) * 0.02))
 * - EF min: 1.3
 */

describe('SRS (SM-2) Algorithm Tests', () => {

    describe('1. Initial State & Basic Ratings', () => {
        it('should correctly handle a new word (Initial State)', () => {
            // Simulator for a new word added to DB
            const initialWord = { interval: 0, repetition: 0, efactor: 2.5 };

            // Test "Easy" (Quality 5) on first appearance
            const result = calculateSm2({ ...initialWord, quality: 5 });
            expect(result.interval).toBe(1);
            expect(result.repetition).toBe(1);
            expect(result.efactor).toBeGreaterThan(2.5); // EF should increase
        });

        it('should handle "Forgot" (Quality 0)', () => {
            const result = calculateSm2({ interval: 10, repetition: 5, efactor: 2.8, quality: 0 });
            expect(result.interval).toBe(1); // Should reset to daily review
            expect(result.repetition).toBe(0); // Should reset repetition
            expect(result.efactor).toBeLessThan(2.8 - 0.5); // Should drop significantly
        });

        it('should handle "Hard" (Quality 3)', () => {
            const result = calculateSm2({ interval: 10, repetition: 5, efactor: 2.5, quality: 3 });
            expect(result.repetition).toBe(6);
            expect(result.efactor).toBeLessThan(2.5); // Quality 3 decreases EF
        });
    });

    describe('2. Rating Sequences', () => {
        it('should follow the correct timeline for "Easy -> Forgot -> Hard -> Easy"', () => {
            // Day 0: New word, User rated Easy (5)
            let state = calculateSm2({ interval: 0, repetition: 0, efactor: 2.5, quality: 5 });
            expect(state.interval).toBe(1);
            expect(state.repetition).toBe(1);

            // Day 1: User reviewed, Forgot (0)
            state = calculateSm2({ interval: state.interval, repetition: state.repetition, efactor: state.efactor, quality: 0 });
            expect(state.interval).toBe(1);
            expect(state.repetition).toBe(0);
            const efAfteForgot = state.efactor;

            // Day 2: User reviewed again, Hard (3)
            state = calculateSm2({ interval: state.interval, repetition: state.repetition, efactor: state.efactor, quality: 3 });
            expect(state.interval).toBe(1);
            expect(state.repetition).toBe(1);
            expect(state.efactor).toBeLessThan(efAfteForgot);

            // Next session (Day 3ish): User rated Easy (5)
            state = calculateSm2({ interval: state.interval, repetition: state.repetition, efactor: state.efactor, quality: 5 });
            // Repetition was 1, so next interval is 6 (+/- fuzz 1)
            expect(state.interval).toBeGreaterThanOrEqual(5);
            expect(state.interval).toBeLessThanOrEqual(7);
            expect(state.repetition).toBe(2);
        });
    });

    describe('3. Boundary Cases', () => {
        it('should clamp E-Factor to a minimum of 1.3 even with continuous forgetting', () => {
            let state = { interval: 1, repetition: 1, efactor: 1.4 };

            // Forget once
            let result = calculateSm2({ ...state, quality: 0 });
            // Forget again using result
            result = calculateSm2({
                interval: result.interval,
                repetition: result.repetition,
                efactor: result.efactor,
                quality: 0
            });

            expect(result.efactor).toBe(1.3);
        });

        it('should increase E-Factor steadily with continuous Easy ratings', () => {
            let state = { interval: 1, repetition: 1, efactor: 2.5 };

            // 5 consecutive Easy ratings
            for (let i = 0; i < 5; i++) {
                state = calculateSm2({ ...state, quality: 5 });
            }

            expect(state.efactor).toBeGreaterThan(3.0);
            expect(state.interval).toBeGreaterThan(50); // Compounding effect
        });
    });

    describe('4. Aggregate Simulation (Distribution Test)', () => {
        it('should simulate a 30-day review cycle for 100 words', () => {
            const NUM_WORDS = 100;
            const DAYS = 30;

            const todayStart = new Date();
            todayStart.setHours(4, 0, 0, 0);

            // Pool of 100 new words, all due today
            let words = Array.from({ length: NUM_WORDS }, () => ({
                id: Math.random().toString(),
                interval: 0,
                repetition: 0,
                efactor: 2.5,
                nextReview: new Date(todayStart)
            }));

            const reviewsPerDay: number[] = new Array(DAYS).fill(0);

            for (let day = 0; day < DAYS; day++) {
                const currentDay = new Date(todayStart);
                currentDay.setDate(currentDay.getDate() + day);

                words.forEach((word, index) => {
                    if (word.nextReview <= currentDay) {
                        reviewsPerDay[day]++;

                        // Simulate random user performance: 70% Good/Easy, 20% Hard, 10% Forgot
                        const rand = Math.random();
                        let quality = 5;
                        if (rand < 0.1) quality = 0;
                        else if (rand < 0.3) quality = 3;
                        else if (rand < 0.6) quality = 4;

                        const result = calculateSm2({
                            interval: word.interval,
                            repetition: word.repetition,
                            efactor: word.efactor,
                            quality
                        });

                        words[index] = {
                            ...word,
                            interval: result.interval,
                            repetition: result.repetition,
                            efactor: result.efactor,
                            nextReview: result.nextReview
                        };
                    }
                });
            }

            // High-level verification:
            // 1. Every day should have some reviews (after day 1)
            // 2. Total reviews should be significantly higher than NUM_WORDS due to repetition
            const totalReviews = reviewsPerDay.reduce((a, b) => a + b, 0);

            expect(reviewsPerDay[0]).toBe(NUM_WORDS); // Day 0 all new words
            expect(totalReviews).toBeGreaterThan(NUM_WORDS * 2);

            // Distribution check: No single day should be 0 after initial ramp-up
            reviewsPerDay.slice(1, 10).forEach(count => {
                expect(count).toBeGreaterThan(0);
            });

            console.log('Daily Review Distribution (100 words, 30 days):', reviewsPerDay);
        });
    });
});

export interface Sm2Input {
  interval: number;
  repetition: number;
  efactor: number;
  quality: number;
}

export interface Sm2Output {
  interval: number;
  repetition: number;
  efactor: number;
  nextReview: Date;
}

/**
 * Calculates the next review schedule using the SM-2 algorithm with improvements.
 * Improvements:
 * - Minimum E-Factor is 1.3 (as per SM-2 spec).
 * - Adds "fuzz" (random variance) to intervals > 4 days to prevent card clumping.
 * - Standardizes review time to 4:00 AM next day (start of day).
 */
export function calculateSm2(input: Sm2Input): Sm2Output {
  let { interval, repetition, efactor, quality } = input;
  let nextInterval = 0;
  let nextRepetition = 0;
  let nextEfactor = efactor;

  if (quality >= 3) {
    if (repetition === 0) {
      nextInterval = 1;
    } else if (repetition === 1) {
      nextInterval = 6;
    } else {
      nextInterval = Math.round(interval * efactor);
    }
    nextRepetition = repetition + 1;
  } else {
    nextInterval = 1;
    nextRepetition = 0;
  }

  // Calculate new Ease Factor: EF' = EF + (0.1 - (5-q)*(0.08 + (5-q)*0.02))
  nextEfactor = efactor + (0.1 - (5 - quality) * (0.08 + (5 - quality) * 0.02));
  if (nextEfactor < 1.3) nextEfactor = 1.3;

  // --- FUZZ LOGIC ---
  // Only fuzz if interval is large enough (> 4 days) to avoid messing up short-term learning
  if (nextInterval > 4) {
    const fuzzFactor = 0.05; // 5% variance
    const fuzz = Math.ceil(nextInterval * fuzzFactor);
    // Randomly add or subtract fuzz, but ensure interval checks logic
    const randomFuzz = Math.floor(Math.random() * (fuzz * 2 + 1)) - fuzz;
    nextInterval += randomFuzz;
    
    // Ensure interval doesn't drop below previous repetition logic boundaries too much, 
    // but essential constraint is > 0
    if (nextInterval < 1) nextInterval = 1;
  }

  const nextReviewDate = new Date();
  nextReviewDate.setDate(nextReviewDate.getDate() + nextInterval);
  // Set to 4:00 AM to align with day start logic
  nextReviewDate.setHours(4, 0, 0, 0);

  return {
    interval: nextInterval,
    repetition: nextRepetition,
    efactor: nextEfactor,
    nextReview: nextReviewDate
  };
}

import { auth } from '@/auth';
import { prisma } from '@/lib/prisma';

export async function getAuthenticatedUser() {
    const session = await auth();
    if (!session?.user?.email) return null;

    const email = session.user.email;
    // Try exact match first
    let user = await prisma.user.findUnique({ where: { email } });

    // Fallback to case-insensitive if not found
    if (!user) {
        console.warn(`User not found by exact email: ${email}. Trying case-insensitive lookup.`);
        // Use raw query to force case-insensitive check on SQLite
        // & re-fetch to ensure valid Date objects and types
        try {
            const users = await prisma.$queryRawUnsafe<any[]>(
                `SELECT id FROM "User" WHERE LOWER(email) = LOWER(?) LIMIT 1`,
                email
            );
            if (users && users.length > 0) {
                user = await prisma.user.findUnique({ where: { id: users[0].id } });
            }
        } catch (e) {
            console.error("Error during case-insensitive lookup:", e);
        }
    }

    if (!user) {
        console.warn(`User absolutely not found for email: ${email}. Auto-creating user to recover session state.`);
        try {
            // Auto-create user to fix "User not found" error when session exists but DB is empty
            // Use a dummy hash for password since they are already authenticated via session
            // Next login will fail unless they register again or reset password, but current session works.
            user = await prisma.user.create({
                data: {
                    email: email,
                    name: session.user.name || email.split('@')[0],
                    password: "$2a$10$UserWasAutoCreatedFromSessionButDBWasWiped", // Dummy hash
                    dailyNewWordGoal: 20,
                    dailyNewGrammarGoal: 10
                }
            });
        } catch (createError) {
            console.error("Error auto-creating user:", createError);
        }
    }

    return user;
}

/**
 * Normalizes messy word types from the database into a standard set of categories.
 */
export function normalizeWordType(wordType: string | null | undefined): string {
    if (!wordType) return "Khác";
    const type = wordType.toLowerCase().trim();

    // Stricter checks for single letter labels to avoid substrings in "phrase", "verb", etc.
    const isNoun = ["noun", "danh từ", "dt", "n.", "danh từ/cụm từ", "danh từ/tính từ"].some(t => type.includes(t)) || type === "n";
    const isVerb = ["verb", "động từ", "đt", "v.", "cụm động từ"].some(t => type.includes(t)) || type === "v";
    const isAdj = ["adj", "tính từ", "tt", "adj.", "adjective"].some(t => type.includes(t)) || type === "a";
    const isAdv = ["adv", "trạng từ", "tr", "adv.", "adverb", "phó từ"].some(t => type.includes(t));
    const isPhrase = ["phr", "phrase", "cụm từ", "phr.", "cụm"].some(t => type.includes(t));
    const isIdiom = ["idiom", "thành ngữ", "idm"].some(t => type.includes(t));
    const isPrep = ["prep", "giới từ", "pre"].some(t => type.includes(t));

    // Order matters: More specific types first
    if (isPhrase) return "Cụm từ";
    if (isIdiom) return "Thành ngữ";
    if (isAdv) return "Trạng từ";
    if (isAdj) return "Tính từ";
    if (isNoun) return "Danh từ";
    if (isVerb) return "Động từ";
    if (isPrep) return "Giới từ";

    return "Khác";
}

/**
 * Returns Tailwind CSS classes for labels based on the word type.
 */
export function getWordTypeColor(wordType: string | null | undefined): string {
    return getWordTypeStyles(wordType).bg;
}

/**
 * Returns an object with specific Tailwind color classes for the word type.
 */
export function getWordTypeStyles(wordType: string | null | undefined) {
    const normalized = normalizeWordType(wordType);

    switch (normalized) {
        case "Danh từ": return { bg: "bg-blue-600", border: "border-blue-600", text: "text-blue-600", ring: "ring-blue-600" };
        case "Động từ": return { bg: "bg-emerald-600", border: "border-emerald-600", text: "text-emerald-600", ring: "ring-emerald-600" };
        case "Tính từ": return { bg: "bg-rose-600", border: "border-rose-600", text: "text-rose-600", ring: "ring-rose-600" };
        case "Trạng từ": return { bg: "bg-amber-600", border: "border-amber-600", text: "text-amber-600", ring: "ring-amber-600" };
        case "Cụm từ": return { bg: "bg-indigo-600", border: "border-indigo-600", text: "text-indigo-600", ring: "ring-indigo-600" };
        case "Thành ngữ": return { bg: "bg-purple-600", border: "border-purple-600", text: "text-purple-600", ring: "ring-purple-600" };
        case "Giới từ": return { bg: "bg-cyan-600", border: "border-cyan-600", text: "text-cyan-600", ring: "ring-cyan-600" };
        default: return { bg: "bg-slate-600", border: "border-slate-600", text: "text-slate-600", ring: "ring-slate-600" };
    }
}

/**
 * Pronounces text using the browser's Speech Synthesis API.
 * Supports US, UK, and AU accents from localStorage.
 */
export function speak(text: string) {
    if (typeof window !== "undefined" && window.speechSynthesis) {
        window.speechSynthesis.cancel();

        const utterance = new SpeechSynthesisUtterance(text);

        // Get preferred accent from localStorage (default to US)
        const accent = localStorage.getItem("vocabee-accent") || "US";
        const accentMap: Record<string, string> = {
            "US": "en-US",
            "UK": "en-GB",
            "AU": "en-AU"
        };

        utterance.lang = accentMap[accent] || "en-US";
        utterance.rate = 0.9;
        window.speechSynthesis.speak(utterance);
    }
}

/**
 * Exports data to a CSV file and triggers download.
 */
export function exportToCSV(data: any[], filename: string) {
    if (data.length === 0) return;

    const headers = Object.keys(data[0]).filter(k => k !== 'id' && k !== 'userId' && k !== 'createdAt' && k !== 'updatedAt' && k !== 'nextReview' && k !== 'interval' && k !== 'repetition' && k !== 'efactor');
    const csvContent = [
        headers.join(','),
        ...data.map(row => headers.map(header => {
            const cell = row[header] === null || row[header] === undefined ? "" : row[header];
            // Escape quotes and wrap in quotes if contains comma
            const stringified = String(cell).replace(/"/g, '""');
            return stringified.includes(',') ? `"${stringified}"` : stringified;
        }).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", filename);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
}

/**
 * Enhanced CSV parser with support for Vietnamese headers and different locales.
 */
export function parseCSV(text: string): any[] {
    const lines = text.split(/\r?\n/).filter(line => line.trim().length > 0);
    if (lines.length < 2) return [];

    // Mapping of possible Excel headers to internal keys
    const headerMap: Record<string, string> = {
        "từ vựng": "word",
        "word": "word",
        "nghĩa tiếng việt": "meaning",
        "meaning": "meaning",
        "loại từ": "wordType",
        "type": "wordType",
        "phiên âm": "pronunciation",
        "pronunciation": "pronunciation",
        "từ đồng nghĩa": "synonyms",
        "synonyms": "synonyms",
        "ví dụ toeic": "example",
        "ví dụ": "example",
        "example": "example"
    };

    // Detect delimiter (comma or semicolon)
    const headerLine = lines[0];
    const delimiter = headerLine.includes(';') && !headerLine.includes(',') ? ';' : ',';

    const rawHeaders = headerLine.split(delimiter).map(h => h.trim().toLowerCase());
    const result = [];

    for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        // Split by delimiter considering quotes
        const regex = new RegExp(`${delimiter}(?=(?:(?:[^"]*"){2})*[^"]*$)`);
        const values = line.split(regex);

        const obj: any = {};
        rawHeaders.forEach((rawHeader, index) => {
            const internalKey = headerMap[rawHeader];
            if (internalKey) {
                let val = values[index]?.trim() || "";
                // Remove surrounding quotes and handle escaped quotes
                if (val.startsWith('"') && val.endsWith('"')) {
                    val = val.substring(1, val.length - 1).replace(/""/g, '"');
                }
                obj[internalKey] = val;
            }
        });

        // Only add if at least word and meaning exist
        if (obj.word && obj.meaning) {
            result.push(obj);
        }
    }
    return result;
}

/**
 * Specialized CSV parser for Grammar Cards
 */
export function parseGrammarCSV(text: string): any[] {
    // Remove BOM if present (happens often with Excel CSV)
    const cleanText = text.replace(/^\uFEFF/, '');
    const lines = cleanText.split(/\r?\n/).filter(line => line.trim().length > 0);
    if (lines.length < 2) return [];

    const headerLine = lines[0];

    // Improved delimiter detection: check for Tab, Semicolon, or Comma
    let delimiter = ',';
    if (headerLine.includes('\t')) delimiter = '\t';
    else if (headerLine.includes(';') && !headerLine.includes(',')) delimiter = ';';
    else if (headerLine.includes(',') && !headerLine.includes(';')) delimiter = ',';
    else if (headerLine.includes(';')) delimiter = ';'; // Favor semicolon if both exist (Excel EU/VN style)

    const rawHeaders = headerLine.split(delimiter).map(h => h.trim().toLowerCase());

    // Exact mapping for grammar (including user's common headers)
    const headerMap: Record<string, string> = {
        "type": "type",
        "loại": "type",
        "prompt": "prompt",
        "câu hỏi": "prompt",
        "đề bài": "prompt",
        "short example": "prompt",
        "ví dụ": "prompt",
        "answer": "answer",
        "đáp án": "answer",
        "practice activity": "answer",
        "bài tập": "answer",
        "options": "options",
        "lựa chọn": "options",
        "explanation": "explanation",
        "giải thích": "explanation",
        "what to master": "explanation",
        "kiến thức": "explanation",
        "hint": "hint",
        "gợi ý": "hint",
        "tags": "tags",
        "nhãn": "tags",
        "topic": "topic",
        "chủ đề": "topic",
        "subtopic": "subtopic"
    };

    const result = [];
    for (let i = 1; i < lines.length; i++) {
        const line = lines[i].trim();
        if (!line) continue;

        const regex = new RegExp(`${delimiter}(?=(?:(?:[^"]*"){2})*[^"]*$)`);
        const values = line.split(regex);

        const obj: any = {};
        rawHeaders.forEach((rawHeader, index) => {
            const internalKey = headerMap[rawHeader];
            if (internalKey) {
                let val = values[index]?.trim() || "";
                if (val.startsWith('"') && val.endsWith('"')) {
                    val = val.substring(1, val.length - 1).replace(/""/g, '"');
                }
                obj[internalKey] = val;
            }
        });

        // Smart Mapping & Defaults
        const finalObj: any = {
            type: obj.type || "PRODUCTION",
            prompt: obj.prompt || "",
            answer: obj.answer || "",
            options: obj.options || null,
            hint: obj.hint || "",
            explanation: obj.explanation || "",
            tags: obj.tags || ""
        };

        // If user provided topic/subtopic but no tags, combine them
        if (!finalObj.tags && (obj.topic || obj.subtopic)) {
            finalObj.tags = [obj.topic, obj.subtopic].filter(Boolean).join(", ");
        }

        if (finalObj.prompt && finalObj.answer) {
            result.push(finalObj);
        }
    }
    return result;
}

export function cn(...inputs: any[]) {
    return inputs.flat().filter(Boolean).join(" ");
}

